import{_ as i,o as l,c as t,a2 as e}from"./chunks/framework.DnrXFDHb.js";const F=JSON.parse('{"title":"F05: 應收帳款品質與收款天數 - finance-financial-analyst 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8064_東捷/20260429/F05_應收帳款品質與收款天數_財務分析專家.md","filePath":"審計報告庫/財務審計/8064_東捷/20260429/F05_應收帳款品質與收款天數_財務分析專家.md"}'),n={name:"審計報告庫/財務審計/8064_東捷/20260429/F05_應收帳款品質與收款天數_財務分析專家.md"};function r(o,a,s,c,h,d){return l(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="f05-應收帳款品質與收款天數-finance-financial-analyst-審計報告" tabindex="-1">F05: 應收帳款品質與收款天數 - finance-financial-analyst 審計報告 <a class="header-anchor" href="#f05-應收帳款品質與收款天數-finance-financial-analyst-審計報告" aria-label="Permalink to &quot;F05: 應收帳款品質與收款天數 - finance-financial-analyst 審計報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p></blockquote><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>應收帳款 (AR) 的規模與週轉天數 (DSO) 變動為何？是否存在客戶拖欠或虛增營收風險？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>DSO 由 116 天降至 72 天，AR 規模縮減 32%。B 客戶流失結構性導正 AR，逾期比降至 29%，獲利品質轉穩健。評級 A。（54字）</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>： <ul><li>DSO 趨勢（平均淨 AR / 營收 × 365）：FY2023 116 天 → FY2024 115 天 → FY2025 72 天，YoY 改善 37%</li><li>AR 規模：淨額 FY2023 $982M → FY2024 $655M（↓33%） → FY2025 $477M（↓27%）</li><li>營收：FY2023 $2,990M → FY2024 $2,604M（↓13%） → FY2025 $2,871M（↑10%）</li><li>逾期款項佔比（&gt;180 天）：FY2023 46.4% → FY2025 29.3%，優化 17pp</li></ul></li><li><strong>診斷見解</strong>：DSO 收斂反映兩項結構改善：① 最大客戶 B 營收萎縮，其拖欠型 AR 隨之出表；② FY2025 迴轉 $57.9M 預期信用損失，因帳款收回沖回，非人為調節。AR 衰退快於營收，為正面背離。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="收款天數實測與趨勢-dso-analysis" tabindex="-1">收款天數實測與趨勢（DSO Analysis） <a class="header-anchor" href="#收款天數實測與趨勢-dso-analysis" aria-label="Permalink to &quot;收款天數實測與趨勢（DSO Analysis）&quot;">​</a></h3><ul><li><strong>核心重點</strong>：DSO（平均淨 AR）由 FY2023 115.7 天 → FY2025 71.9 天，壓縮 37.8%。</li><li><strong>深度見解</strong>：DSO 改善來自 B 客戶 AR 集中度驟降——FY2024 底 B 客戶應收 $309.8M（總 AR 42%），FY2025 底降至 $68.7M。B 客戶營收從 $947M（36%）腰斬至 $303M（11%），連動長期逾期應收（731-1095天）從 $122.9M 急降至 $16.6M。此為高風險客戶退場的被動淨化，非營運效率自然提升。</li></ul><h3 id="ar-成長率-vs-營收成長率-背離測試" tabindex="-1">AR 成長率 vs 營收成長率：背離測試 <a class="header-anchor" href="#ar-成長率-vs-營收成長率-背離測試" aria-label="Permalink to &quot;AR 成長率 vs 營收成長率：背離測試&quot;">​</a></h3><ul><li><strong>核心重點</strong>：背離指標——FY2024 AR↓27% vs 營收↓13%（正向瘦身）；FY2025 AR↓35% vs 營收↑10%（最佳組合）。</li><li><strong>深度見解</strong>：FY2023 曾發生死亡交叉：營收驟降 24%，AR 反增 8%，AR 僵固反映前期超額應收（DSO 從 87 暴漲至 116 天），證實 FY2022-FY2023 確有放帳衝業績痕跡。FY2024 起帳款回收行動見效，至 FY2025 已完全修正，無持續虛增營收之虞。</li></ul><h3 id="壞帳準備審查" tabindex="-1">壞帳準備審查 <a class="header-anchor" href="#壞帳準備審查" aria-label="Permalink to &quot;壞帳準備審查&quot;">​</a></h3><ul><li><strong>核心重點</strong>：備抵率 FY2024 11.8% → FY2025 5.6%。提列變動：FY2024 提列 $49.3M，FY2025 迴轉 $57.9M。</li><li><strong>深度見解</strong>：FY2025 備抵率與 DSO 同步下降，邏輯一致。FY2024 提列的 $102.4M 超 730 天帳款在 FY2025 透過回款順利出表。FY2025 底超 730 天帳款僅 $30.3M（總 AR 6%），公司已按 50-100% 提列 $18.7M 備抵，覆蓋充足，無調節損益跡象。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一：「迴轉利益 = 一次性美化」誤判</strong>：FY2025 損益表因 $57.9M 呆帳迴轉而虛增獲利，若剔除該項，稅前淨利將縮水。但核對帳齡表可知：迴轉來自實際收回的超 730 天逾期款項（$102.4M→$16.6M），為真實現金回流，非會計擺盪。風險在於 FY2026 若無等同規模回沖，EPS 可能出現 YoY 基期效應衰退。</li><li><strong>空頭風險二：客戶集中度轉移仍存不確定性</strong>：FY2025 AR 前三大佔比由 62.7%降至 42.7%，表面分散化。但客戶 A 營收貢獻 $419M（+1,630% YoY）異軍突起，成為最大營收來源。A 客戶 $95.7M 的應收是否健康、帳齡落在何區間，年報未揭露逐客戶帳齡。若 A 客戶發生營運逆風，東捷將面臨新一波 AR 集中風險。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>年報 (8064)</strong>：OK — FY2023-Q4 / FY2024-Q4 / FY2025-Q4 合併財報已完整調閱</li><li><strong>FinMind</strong>：Not used — 年報來源優先，且年報帳齡表已提供完整逾期結構</li><li><strong>yfinance</strong>：Not used — Ticker 8064.TWO 於台灣櫃買市場</li><li><strong>關鍵核對碼</strong>： <ul><li>FY2025 AR 淨額：$476,606 (千元) → 資產負債表 p.8</li><li>FY2025 逾期 &gt;180 天佔比：$154,883 / $529,395 = 29.3% → 附註十 p.32</li><li>FY2025 DSO（平均淨 AR）：($655,059+$476,606)/2 ÷ $2,870,684 × 365 = 71.9 天</li></ul></li></ul>',19)])])}const u=i(n,[["render",r]]);export{F as __pageData,u as default};
